/// NamespaceSelector nil - only objects at VMAuth namespace.
/// If both nil - behaviour controlled by selectAllByDefault
#[derive(Serialize, Deserialize, Clone, Debug, Default, PartialEq)]
pub struct VmAuthUserSelector {
    /// matchExpressions is a list of label selector requirements. The requirements are ANDed.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "matchExpressions")]
    pub match_expressions: Option<Vec<VmAuthUserSelectorMatchExpressions>>,
    /// matchLabels is a map of {key,value} pairs. A single {key,value} in the matchLabels
    /// map is equivalent to an element of matchExpressions, whose key field is "key", the
    /// operator is "In", and the values array contains only "value". The requirements are ANDed.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "matchLabels")]
    pub match_labels: Option<BTreeMap<String, String>>,
}

/// A label selector requirement is a selector that contains values, a key, and an operator that
/// relates the key and values.
#[derive(Serialize, Deserialize, Clone, Debug, Default, PartialEq)]
pub struct VmAuthUserSelectorMatchExpressions {
    /// key is the label key that the selector applies to.
    pub key: String,
    /// operator represents a key's relationship to a set of values.
    /// Valid operators are In, NotIn, Exists and DoesNotExist.
    pub operator: String,
    /// values is an array of string values. If the operator is In or NotIn,
    /// the values array must be non-empty. If the operator is Exists or DoesNotExist,
    /// the values array must be empty. This array is replaced during a strategic
    /// merge patch.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub values: Option<Vec<String>>,
}

/// VolumeMount describes a mounting of a Volume within a container.
#[derive(Serialize, Deserialize, Clone, Debug, Default, PartialEq)]
pub struct VmAuthVolumeMounts {
    /// Path within the container at which the volume should be mounted.  Must
    /// not contain ':'.
    #[serde(rename = "mountPath")]
    pub mount_path: String,
    /// mountPropagation determines how mounts are propagated from the host
    /// to container and the other way around.
    /// When not set, MountPropagationNone is used.
    /// This field is beta in 1.10.
    /// When RecursiveReadOnly is set to IfPossible or to Enabled, MountPropagation must be None or unspecified
    /// (which defaults to None).
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "mountPropagation")]
    pub mount_propagation: Option<String>,
    /// This must match the Name of a Volume.
    pub name: String,
    /// Mounted read-only if true, read-write otherwise (false or unspecified).
    /// Defaults to false.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "readOnly")]
    pub read_only: Option<bool>,
    /// RecursiveReadOnly specifies whether read-only mounts should be handled
    /// recursively.
    /// 
    /// If ReadOnly is false, this field has no meaning and must be unspecified.
    /// 
    /// If ReadOnly is true, and this field is set to Disabled, the mount is not made
    /// recursively read-only.  If this field is set to IfPossible, the mount is made
    /// recursively read-only, if it is supported by the container runtime.  If this
    /// field is set to Enabled, the mount is made recursively read-only if it is
    /// supported by the container runtime, otherwise the pod will not be started and
    /// an error will be generated to indicate the reason.
    /// 
    /// If this field is set to IfPossible or Enabled, MountPropagation must be set to
    /// None (or be unspecified, which defaults to None).
    /// 
    /// If this field is not specified, it is treated as an equivalent of Disabled.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "recursiveReadOnly")]
    pub recursive_read_only: Option<String>,
    /// Path within the volume from which the container's volume should be mounted.
    /// Defaults to "" (volume's root).
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "subPath")]
    pub sub_path: Option<String>,
    /// Expanded path within the volume from which the container's volume should be mounted.
    /// Behaves similarly to SubPath but environment variable references $(VAR_NAME) are expanded using the container's environment.
    /// Defaults to "" (volume's root).
    /// SubPathExpr and SubPath are mutually exclusive.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "subPathExpr")]
    pub sub_path_expr: Option<String>,
}

/// Configures vertical pod autoscaling.
#[derive(Serialize, Deserialize, Clone, Debug, Default, PartialEq)]
pub struct VmAuthVpa {
    /// Recommenders specifies custom VPA recommender names.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub recommenders: Option<Vec<VmAuthVpaRecommenders>>,
    /// ResourcePolicy controls how the autoscaler computes recommended resources per container.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "resourcePolicy")]
    pub resource_policy: Option<VmAuthVpaResourcePolicy>,
    /// UpdatePolicy controls how the autoscaler applies changes to pod resources.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "updatePolicy")]
    pub update_policy: Option<VmAuthVpaUpdatePolicy>,
}

/// VerticalPodAutoscalerRecommenderSelector points to a specific Vertical Pod Autoscaler recommender.
/// In the future it might pass parameters to the recommender.
#[derive(Serialize, Deserialize, Clone, Debug, Default, PartialEq)]
pub struct VmAuthVpaRecommenders {
    /// Name of the recommender responsible for generating recommendation for this object.
    pub name: String,
}

/// ResourcePolicy controls how the autoscaler computes recommended resources per container.
#[derive(Serialize, Deserialize, Clone, Debug, Default, PartialEq)]
pub struct VmAuthVpaResourcePolicy {
    /// Per-container resource policies.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "containerPolicies")]
    pub container_policies: Option<Vec<VmAuthVpaResourcePolicyContainerPolicies>>,
}

/// ContainerResourcePolicy controls how autoscaler computes the recommended
/// resources for a specific container.
#[derive(Serialize, Deserialize, Clone, Debug, Default, PartialEq)]
pub struct VmAuthVpaResourcePolicyContainerPolicies {
    /// Name of the container or DefaultContainerResourcePolicy, in which
    /// case the policy is used by the containers that don't have their own
    /// policy specified.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "containerName")]
    pub container_name: Option<String>,
    /// Specifies the type of recommendations that will be computed
    /// (and possibly applied) by VPA.
    /// If not specified, the default of [ResourceCPU, ResourceMemory] will be used.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "controlledResources")]
    pub controlled_resources: Option<Vec<String>>,
    /// Specifies which resource values should be controlled.
    /// The default is "RequestsAndLimits".
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "controlledValues")]
    pub controlled_values: Option<VmAuthVpaResourcePolicyContainerPoliciesControlledValues>,
    /// Specifies the maximum amount of resources that will be recommended
    /// for the container. The default is no maximum.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "maxAllowed")]
    pub max_allowed: Option<BTreeMap<String, IntOrString>>,
    /// Specifies the minimal amount of resources that will be recommended
    /// for the container. The default is no minimum.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "minAllowed")]
    pub min_allowed: Option<BTreeMap<String, IntOrString>>,
    /// Whether autoscaler is enabled for the container. The default is "Auto".
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub mode: Option<VmAuthVpaResourcePolicyContainerPoliciesMode>,
    /// oomBumpUpRatio is the ratio to increase memory when OOM is detected.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "oomBumpUpRatio")]
    pub oom_bump_up_ratio: Option<IntOrString>,
    /// oomMinBumpUp is the minimum increase in memory when OOM is detected.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "oomMinBumpUp")]
    pub oom_min_bump_up: Option<IntOrString>,
}

/// ContainerResourcePolicy controls how autoscaler computes the recommended
/// resources for a specific container.
#[derive(Serialize, Deserialize, Clone, Debug, PartialEq)]
pub enum VmAuthVpaResourcePolicyContainerPoliciesControlledValues {
    RequestsAndLimits,
    RequestsOnly,
}

/// ContainerResourcePolicy controls how autoscaler computes the recommended
/// resources for a specific container.
#[derive(Serialize, Deserialize, Clone, Debug, PartialEq)]
pub enum VmAuthVpaResourcePolicyContainerPoliciesMode {
    Auto,
    Off,
}

/// UpdatePolicy controls how the autoscaler applies changes to pod resources.
#[derive(Serialize, Deserialize, Clone, Debug, Default, PartialEq)]
pub struct VmAuthVpaUpdatePolicy {
    /// EvictionRequirements is a list of EvictionRequirements that need to
    /// evaluate to true in order for a Pod to be evicted. If more than one
    /// EvictionRequirement is specified, all of them need to be fulfilled to allow eviction.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "evictionRequirements")]
    pub eviction_requirements: Option<Vec<VmAuthVpaUpdatePolicyEvictionRequirements>>,
    /// Minimal number of replicas which need to be alive for Updater to attempt
    /// pod eviction (pending other checks like PDB). Only positive values are
    /// allowed. Overrides global '--min-replicas' flag.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "minReplicas")]
    pub min_replicas: Option<i32>,
    /// Controls when autoscaler applies changes to the pod resources.
    /// The default is 'Recreate'.
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "updateMode")]
    pub update_mode: Option<VmAuthVpaUpdatePolicyUpdateMode>,
}

/// EvictionRequirement defines a single condition which needs to be true in
/// order to evict a Pod
#[derive(Serialize, Deserialize, Clone, Debug, PartialEq)]
pub struct VmAuthVpaUpdatePolicyEvictionRequirements {
    /// EvictionChangeRequirement refers to the relationship between the new target recommendation for a Pod and its current requests, what kind of change is necessary for the Pod to be evicted
    #[serde(rename = "changeRequirement")]
    pub change_requirement: VmAuthVpaUpdatePolicyEvictionRequirementsChangeRequirement,
    /// Resources is a list of one or more resources that the condition applies
    /// to. If more than one resource is given, the EvictionRequirement is fulfilled
    /// if at least one resource meets `changeRequirement`.
    pub resources: Vec<String>,
}

/// EvictionRequirement defines a single condition which needs to be true in
/// order to evict a Pod
#[derive(Serialize, Deserialize, Clone, Debug, PartialEq)]
pub enum VmAuthVpaUpdatePolicyEvictionRequirementsChangeRequirement {
    TargetHigherThanRequests,
    TargetLowerThanRequests,
}

/// UpdatePolicy controls how the autoscaler applies changes to pod resources.
#[derive(Serialize, Deserialize, Clone, Debug, PartialEq)]
pub enum VmAuthVpaUpdatePolicyUpdateMode {
    Off,
    Initial,
    Recreate,
    InPlaceOrRecreate,
    Auto,
}

/// VMAuthStatus defines the observed state of VMAuth
#[derive(Serialize, Deserialize, Clone, Debug, Default, PartialEq)]
pub struct VmAuthStatus {
    /// Known .status.conditions.type are: "Available", "Progressing", and "Degraded"
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub conditions: Option<Vec<Condition>>,
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "lastAppliedSpec")]
    pub last_applied_spec: Option<serde_json::Value>,
    /// ObservedGeneration defines current generation picked by operator for the
    /// reconcile
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "observedGeneration")]
    pub observed_generation: Option<i64>,
    /// Reason defines human readable error reason
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub reason: Option<String>,
    /// UpdateStatus defines a status for update rollout
    #[serde(default, skip_serializing_if = "Option::is_none", rename = "updateStatus")]
    pub update_status: Option<String>,
}

